INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**טיח מזרמק — עובש על הטיח** — נקודות או כתמים כהים על הטיח המעידים על נוכחות עובש. בעיה בריאותית הנובעת מרטיבות מתמשכת ואוורור לקוי.. המלצה: טיפול במקור הרטיבות, ניקוי אנטי-פטרייתי, יישום ציפוי אנטי-עובשי, וצביעה בצבע עמיד ברטיבות. עלות משוערת: ₪100-₪300 (למ"ר)', '**טיח מזרמק — עובש על הטיח** — נקודות או כתמים כהים על הטיח המעידים על נוכחות עובש. בעיה בריאותית הנובעת מרטיבות מתמשכת ואוורור לקוי.. המלצה: טיפול במקור הרטיבות, ניקוי אנטי-פטרייתי, יישום ציפוי אנטי-עובשי, וצביעה בצבע עמיד ברטיבות. עלות משוערת: ₪100-₪300 (למ"ר)', 'ת"י 1415 — טיח חייב להיות יבש ונקי מעובש', 'ת"י 1415 — טיח חייב להיות יבש ונקי מעובש', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**פני שטח טיח גסים — חוסר החלקה** — פני שטח הטיח הפנימי גסים ולא חלקים כנדרש. מקשה על צביעה אחידה ופוגע במראה הסופי.. המלצה: ליטוש מכני של המשטח, מריחת שכבת החלקה דקה, וליטוש סופי. עלות משוערת: ₪30-₪60 (למ"ר)', '**פני שטח טיח גסים — חוסר החלקה** — פני שטח הטיח הפנימי גסים ולא חלקים כנדרש. מקשה על צביעה אחידה ופוגע במראה הסופי.. המלצה: ליטוש מכני של המשטח, מריחת שכבת החלקה דקה, וליטוש סופי. עלות משוערת: ₪30-₪60 (למ"ר)', 'ת"י 1415 — טיח פנימי מוחלק חייב להיות חלק ואחיד ללא גבשושיות או שקעים', 'ת"י 1415 — טיח פנימי מוחלק חייב להיות חלק ואחיד ללא גבשושיות או שקעים', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**עובי טיח לא מספיק** — שכבת הטיח דקה מהנדרש בתקן, מה שמפחית את ההגנה מפני רטיבות ותנאי מזג אוויר ומקצר את אורך חיי הטיח.. המלצה: הוספת שכבת טיח נוספת להשלמת העובי הנדרש, עם שכבת חיבור (ספריץ) בין השכבות. עלות משוערת: ₪60-₪120 (למ"ר)', '**עובי טיח לא מספיק** — שכבת הטיח דקה מהנדרש בתקן, מה שמפחית את ההגנה מפני רטיבות ותנאי מזג אוויר ומקצר את אורך חיי הטיח.. המלצה: הוספת שכבת טיח נוספת להשלמת העובי הנדרש, עם שכבת חיבור (ספריץ) בין השכבות. עלות משוערת: ₪60-₪120 (למ"ר)', 'ת"י 1415 — עובי מינימלי של טיח חיצוני: 20 מ"מ (שתי שכבות). טיח פנימי: 10 מ"מ', 'ת"י 1415 — עובי מינימלי של טיח חיצוני: 20 מ"מ (שתי שכבות). טיח פנימי: 10 מ"מ', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**חוסר חיזוק רשת בטיח על תפר בלוקים-בטון** — טיח שבוצע על תפר בין חומרים שונים (בלוקים ובטון) ללא רשת חיזוק, מה שגורם לסדקים לאורך קו התפר.. המלצה: חשיפת התפר, הדבקת רשת פיברגלס ברוחב 20 ס"מ לפחות על כל אורך התפר, טיוח מחדש. עלות משוערת: ₪40-₪80 (למ"א)', '**חוסר חיזוק רשת בטיח על תפר בלוקים-בטון** — טיח שבוצע על תפר בין חומרים שונים (בלוקים ובטון) ללא רשת חיזוק, מה שגורם לסדקים לאורך קו התפר.. המלצה: חשיפת התפר, הדבקת רשת פיברגלס ברוחב 20 ס"מ לפחות על כל אורך התפר, טיוח מחדש. עלות משוערת: ₪40-₪80 (למ"א)', 'ת"י 1415 — יש להניח רשת טיח על כל תפר בין חומרים שונים (בלוקים/בטון) למניעת סדקים', 'ת"י 1415 — יש להניח רשת טיח על כל תפר בין חומרים שונים (בלוקים/בטון) למניעת סדקים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**סדק כיווץ בטיח** — סדק דק בטיח הנובע מכיווץ והתייבשות. שכיח בחיבורי קירות ובסביבת פתחים.. המלצה: מילוי הסדק בחומר אקרילי גמיש וצביעה מחדש. עלות משוערת: ₪150-₪400 (ליחידה)', '**סדק כיווץ בטיח** — סדק דק בטיח הנובע מכיווץ והתייבשות. שכיח בחיבורי קירות ובסביבת פתחים.. המלצה: מילוי הסדק בחומר אקרילי גמיש וצביעה מחדש. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 1515 — תקן ישראלי לעבודות טיח — סדקי כיווץ עד 0.5 מ"מ נחשבים תקינים', 'ת"י 1515 — תקן ישראלי לעבודות טיח — סדקי כיווץ עד 0.5 מ"מ נחשבים תקינים', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**סדק אלכסוני בטיח** — סדק אלכסוני בטיח, עלול להעיד על תזוזת מבנה או שקיעה דיפרנציאלית. דורש בדיקה הנדסית.. המלצה: בדיקת מהנדס קונסטרוקציה, תיקון בהתאם לממצאים. עלות משוערת: ₪300-₪2000 (ליחידה)', '**סדק אלכסוני בטיח** — סדק אלכסוני בטיח, עלול להעיד על תזוזת מבנה או שקיעה דיפרנציאלית. דורש בדיקה הנדסית.. המלצה: בדיקת מהנדס קונסטרוקציה, תיקון בהתאם לממצאים. עלות משוערת: ₪300-₪2000 (ליחידה)', 'ת"י 1515 — סדק אלכסוני מעל 1 מ"מ מחייב בדיקת מהנדס', 'ת"י 1515 — סדק אלכסוני מעל 1 מ"מ מחייב בדיקת מהנדס', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**בליטות וגבשושיות בטיח** — משטח טיח לא חלק — בליטות, גבשושיות או אי-סדרים במרקם.. המלצה: שיוף מקומי וצביעה מחדש, או טיח מחדש בחלק הפגום. עלות משוערת: ₪200-₪600 (ליחידה)', '**בליטות וגבשושיות בטיח** — משטח טיח לא חלק — בליטות, גבשושיות או אי-סדרים במרקם.. המלצה: שיוף מקומי וצביעה מחדש, או טיח מחדש בחלק הפגום. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1515 — סטייה מותרת של 3 מ"מ ב-2 מטר', 'ת"י 1515 — סטייה מותרת של 3 מ"מ ב-2 מטר', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'טיח ושפכטל', '**טיח מתקלף / מתפורר** — טיח שמתקלף או מתפורר מהקיר, חושף את השכבה שמתחת. עלול להעיד על בעיית רטיבות.. המלצה: הסרת טיח פגום, בדיקת רטיבות, טיח מחדש וצביעה. עלות משוערת: ₪300-₪1200 (ליחידה)', '**טיח מתקלף / מתפורר** — טיח שמתקלף או מתפורר מהקיר, חושף את השכבה שמתחת. עלול להעיד על בעיית רטיבות.. המלצה: הסרת טיח פגום, בדיקת רטיבות, טיח מחדש וצביעה. עלות משוערת: ₪300-₪1200 (ליחידה)', 'ת"י 1515 — טיח חייב להיות צמוד לבסיס — התקלפות מהווה כשל', 'ת"י 1515 — טיח חייב להיות צמוד לבסיס — התקלפות מהווה כשל', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**אריח רצפה שבור או סדוק** — אריח רצפה עם שבר, סדק או פגם גלוי. עלול להיגרם מחבטה, עומס נקודתי, או הדבקה לקויה שגרמה למתח באריח.. המלצה: הסרת האריח הפגום, ניקוי המשטח, הדבקת אריח חדש זהה בדבק מתאים ומילוי רובה. עלות משוערת: ₪150-₪400 (ליחידה)', '**אריח רצפה שבור או סדוק** — אריח רצפה עם שבר, סדק או פגם גלוי. עלול להיגרם מחבטה, עומס נקודתי, או הדבקה לקויה שגרמה למתח באריח.. המלצה: הסרת האריח הפגום, ניקוי המשטח, הדבקת אריח חדש זהה בדבק מתאים ומילוי רובה. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 1555 חלק 3 — אריחי ריצוף חייבים להיות שלמים, ללא סדקים, שברים או פגמים', 'ת"י 1555 חלק 3 — אריחי ריצוף חייבים להיות שלמים, ללא סדקים, שברים או פגמים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**אריח רצפה רופף — חלל מתחת לאריח** — אריח רצפה שאינו מודבק כראוי ויש חלל בינו לבין המצע. ניתן לזהות על ידי הקשה — צליל חלול. על פי התקן, כיסוי הדבק חייב להיות מינימום 65%.. המלצה: הרמת האריח, ניקוי המשטח מדבק ישן, הדבקה מחדש בשיטת סרוק כפול (דבק על המצע ועל גב האריח), מילוי רובה. עלות משוערת: ₪120-₪300 (ליחידה)', '**אריח רצפה רופף — חלל מתחת לאריח** — אריח רצפה שאינו מודבק כראוי ויש חלל בינו לבין המצע. ניתן לזהות על ידי הקשה — צליל חלול. על פי התקן, כיסוי הדבק חייב להיות מינימום 65%.. המלצה: הרמת האריח, ניקוי המשטח מדבק ישן, הדבקה מחדש בשיטת סרוק כפול (דבק על המצע ועל גב האריח), מילוי רובה. עלות משוערת: ₪120-₪300 (ליחידה)', 'ת"י 1555 חלק 3 — כיסוי הדבק מתחת לאריח חייב להיות מינימום 65% משטח האריח, ובאזורים רטובים 80%', 'ת"י 1555 חלק 3 — כיסוי הדבק מתחת לאריח חייב להיות מינימום 65% משטח האריח, ובאזורים רטובים 80%', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**הפרשי גובה בין אריחי רצפה — שיניים** — הפרש גובה (שן) בין אריחים סמוכים. גורם למעידה, ומהווה ליקוי אסתטי ובטיחותי כאחד.. המלצה: ליטוש מקומי של השן באמצעות מכונת ליטוש יהלום, או החלפת האריח הבולט והדבקתו מחדש בגובה הנכון. עלות משוערת: ₪80-₪200 (ליחידה)', '**הפרשי גובה בין אריחי רצפה — שיניים** — הפרש גובה (שן) בין אריחים סמוכים. גורם למעידה, ומהווה ליקוי אסתטי ובטיחותי כאחד.. המלצה: ליטוש מקומי של השן באמצעות מכונת ליטוש יהלום, או החלפת האריח הבולט והדבקתו מחדש בגובה הנכון. עלות משוערת: ₪80-₪200 (ליחידה)', 'ת"י 1555 חלק 3 — הפרש גובה מקסימלי מותר בין אריחים סמוכים: 1 מ"מ לריצוף רגיל, 0.5 מ"מ לריצוף מוחלק', 'ת"י 1555 חלק 3 — הפרש גובה מקסימלי מותר בין אריחים סמוכים: 1 מ"מ לריצוף רגיל, 0.5 מ"מ לריצוף מוחלק', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**חוסר מישוריות בריצוף** — משטח הרצפה אינו ישר — שקעים או בליטות. ניתן לבדוק באמצעות סרגל ישר באורך 2 מ''. מונע הנחה תקינה של ריהוט.. המלצה: פירוק אריחים באזור הבעייתי, יישור תשתית המצע, והדבקה מחדש בשיטה תקנית. עלות משוערת: ₪120-₪250 (למ"ר)', '**חוסר מישוריות בריצוף** — משטח הרצפה אינו ישר — שקעים או בליטות. ניתן לבדוק באמצעות סרגל ישר באורך 2 מ''. מונע הנחה תקינה של ריהוט.. המלצה: פירוק אריחים באזור הבעייתי, יישור תשתית המצע, והדבקה מחדש בשיטה תקנית. עלות משוערת: ₪120-₪250 (למ"ר)', 'ת"י 1555 חלק 3 — סטייה מקסימלית מותרת ממישוריות: 3 מ"מ לכל 2 מטר אורך', 'ת"י 1555 חלק 3 — סטייה מקסימלית מותרת ממישוריות: 3 מ"מ לכל 2 מטר אורך', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**רובה חסרה או פגומה** — חוסר ברובה (פוגה) בין האריחים או רובה שבורה ומתפוררת. מאפשר חדירת מים ולכלוך בין האריחים.. המלצה: ניקוי הרובה הישנה, מילוי מחדש ברובה תקנית בצבע מתאים, ניקוי עודפים. עלות משוערת: ₪30-₪60 (למ"ר)', '**רובה חסרה או פגומה** — חוסר ברובה (פוגה) בין האריחים או רובה שבורה ומתפוררת. מאפשר חדירת מים ולכלוך בין האריחים.. המלצה: ניקוי הרובה הישנה, מילוי מחדש ברובה תקנית בצבע מתאים, ניקוי עודפים. עלות משוערת: ₪30-₪60 (למ"ר)', 'ת"י 1555 חלק 3 — כל המרווחים בין אריחים חייבים להיות מלאים ברובה באופן אחיד', 'ת"י 1555 חלק 3 — כל המרווחים בין אריחים חייבים להיות מלאים ברובה באופן אחיד', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**שיפוע לקוי בריצוף מרפסת/מקלחת** — שיפוע הריצוף אינו מספיק או שהוא בכיוון הלא נכון, מה שגורם להצטברות מים על הרצפה במקום ניקוז לעבר הנקז.. המלצה: פירוק הריצוף באזור הבעייתי, תיקון שכבת השיפוע, ריצוף מחדש עם בדיקת שיפוע. עלות משוערת: ₪200-₪450 (למ"ר)', '**שיפוע לקוי בריצוף מרפסת/מקלחת** — שיפוע הריצוף אינו מספיק או שהוא בכיוון הלא נכון, מה שגורם להצטברות מים על הרצפה במקום ניקוז לעבר הנקז.. המלצה: פירוק הריצוף באזור הבעייתי, תיקון שכבת השיפוע, ריצוף מחדש עם בדיקת שיפוע. עלות משוערת: ₪200-₪450 (למ"ר)', 'ת"י 1555 חלק 3 — שיפוע מינימלי נדרש של 1.5% לכיוון הנקז באזורים רטובים ומרפסות', 'ת"י 1555 חלק 3 — שיפוע מינימלי נדרש של 1.5% לכיוון הנקז באזורים רטובים ומרפסות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**מרווח לא אחיד בין אריחים** — רוחב הרובה אינו אחיד בין האריחים — מרווחים משתנים בגודלם. פוגע באסתטיקה ומעיד על עבודה לא מקצועית.. המלצה: באזורים קטנים — מילוי רובה מחדש. באזורים נרחבים — פירוק והנחה מחדש עם צלבונים. עלות משוערת: ₪60-₪150 (למ"ר)', '**מרווח לא אחיד בין אריחים** — רוחב הרובה אינו אחיד בין האריחים — מרווחים משתנים בגודלם. פוגע באסתטיקה ומעיד על עבודה לא מקצועית.. המלצה: באזורים קטנים — מילוי רובה מחדש. באזורים נרחבים — פירוק והנחה מחדש עם צלבונים. עלות משוערת: ₪60-₪150 (למ"ר)', 'ת"י 1555 חלק 3 — מרווח הרובה חייב להיות אחיד בכל הריצוף עם סטייה מותרת של עד 1 מ"מ', 'ת"י 1555 חלק 3 — מרווח הרובה חייב להיות אחיד בכל הריצוף עם סטייה מותרת של עד 1 מ"מ', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**אריח חיפוי קיר רופף** — אריח חיפוי קיר שאינו מודבק כראוי ונע בלחיצה. מהווה סכנה ליפול ולגרום לפציעה.. המלצה: הסרת האריח, ניקוי מלא של הדבק הישן מהקיר ומגב האריח, הדבקה מחדש בדבק C2 עם סרוק כפול. עלות משוערת: ₪100-₪250 (ליחידה)', '**אריח חיפוי קיר רופף** — אריח חיפוי קיר שאינו מודבק כראוי ונע בלחיצה. מהווה סכנה ליפול ולגרום לפציעה.. המלצה: הסרת האריח, ניקוי מלא של הדבק הישן מהקיר ומגב האריח, הדבקה מחדש בדבק C2 עם סרוק כפול. עלות משוערת: ₪100-₪250 (ליחידה)', 'ת"י 1555 חלק 3 — כיסוי הדבק באריחי קיר חייב להיות מינימום 80% משטח האריח', 'ת"י 1555 חלק 3 — כיסוי הדבק באריחי קיר חייב להיות מינימום 80% משטח האריח', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**אריח חיפוי קיר סדוק** — סדק באריח חיפוי קיר. עלול להיגרם ממתח פנימי כתוצאה מהדבקה לקויה, תזוזת מבנה, או חבטה.. המלצה: החלפת האריח הסדוק באריח חדש זהה, הדבקה בדבק C2 ומילוי רובה. עלות משוערת: ₪120-₪300 (ליחידה)', '**אריח חיפוי קיר סדוק** — סדק באריח חיפוי קיר. עלול להיגרם ממתח פנימי כתוצאה מהדבקה לקויה, תזוזת מבנה, או חבטה.. המלצה: החלפת האריח הסדוק באריח חדש זהה, הדבקה בדבק C2 ומילוי רובה. עלות משוערת: ₪120-₪300 (ליחידה)', 'ת"י 1555 חלק 3 — אריחי חיפוי חייבים להיות שלמים וללא סדקים', 'ת"י 1555 חלק 3 — אריחי חיפוי חייבים להיות שלמים וללא סדקים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**חוסר התאמת דוגמה/כיוון אריחים** — אריחים שהונחו בכיוון לא נכון או שהדוגמה אינה מותאמת ביניהם. בולט בעיקר באריחי שיש או אריחים עם גידים.. המלצה: החלפת האריחים שהונחו שלא כדין והנחתם מחדש בכיוון הנכון. עלות משוערת: ₪150-₪350 (למ"ר)', '**חוסר התאמת דוגמה/כיוון אריחים** — אריחים שהונחו בכיוון לא נכון או שהדוגמה אינה מותאמת ביניהם. בולט בעיקר באריחי שיש או אריחים עם גידים.. המלצה: החלפת האריחים שהונחו שלא כדין והנחתם מחדש בכיוון הנכון. עלות משוערת: ₪150-₪350 (למ"ר)', 'ת"י 1555 חלק 3 — אריחים עם דוגמה או כיוון מוגדר חייבים להיות מונחים בהתאמה ובכיוון אחיד', 'ת"י 1555 חלק 3 — אריחים עם דוגמה או כיוון מוגדר חייבים להיות מונחים בהתאמה ובכיוון אחיד', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**חיתוך אריח לא מדויק** — אריחים שנחתכו בצורה לא מדויקת — קצוות משוננים, לא ישרים, או חיתוכים רחבים מדי/צרים מדי סביב צנרת או פתחים.. המלצה: הסרת האריח הפגום וחיתוך מחדש באמצעות מסור רטוב מקצועי, הדבקה ומילוי רובה. עלות משוערת: ₪100-₪250 (ליחידה)', '**חיתוך אריח לא מדויק** — אריחים שנחתכו בצורה לא מדויקת — קצוות משוננים, לא ישרים, או חיתוכים רחבים מדי/צרים מדי סביב צנרת או פתחים.. המלצה: הסרת האריח הפגום וחיתוך מחדש באמצעות מסור רטוב מקצועי, הדבקה ומילוי רובה. עלות משוערת: ₪100-₪250 (ליחידה)', 'ת"י 1555 חלק 3 — חיתוכי אריחים חייבים להיות נקיים ומדויקים ללא שברים בקצוות', 'ת"י 1555 חלק 3 — חיתוכי אריחים חייבים להיות נקיים ומדויקים ללא שברים בקצוות', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**חוסר בנוטפים (כיוון נטייה) באדן חלון** — אדן חלון מרוצף ללא שיפוע כלפי חוץ ו/או ללא חריץ נוטפים, מה שמאפשר למים לזרום לעבר הקיר ולגרום לרטיבות.. המלצה: התקנת אדן חדש עם שיפוע מינימלי של 3% כלפי חוץ וחריץ נוטפים בתחתית. עלות משוערת: ₪200-₪500 (ליחידה)', '**חוסר בנוטפים (כיוון נטייה) באדן חלון** — אדן חלון מרוצף ללא שיפוע כלפי חוץ ו/או ללא חריץ נוטפים, מה שמאפשר למים לזרום לעבר הקיר ולגרום לרטיבות.. המלצה: התקנת אדן חדש עם שיפוע מינימלי של 3% כלפי חוץ וחריץ נוטפים בתחתית. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 1555 חלק 3 — אדני חלון חיצוניים חייבים לכלול שיפוע כלפי חוץ וחריץ נוטפים', 'ת"י 1555 חלק 3 — אדני חלון חיצוניים חייבים לכלול שיפוע כלפי חוץ וחריץ נוטפים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**קובייה רטט לקויה — חלל מתחת לריצוף חיצוני** — אריחי ריצוף מרפסת או שביל חיצוני עם חללים מתחתיהם, נשמע צליל חלול בהקשה. מסוכן במיוחד במרפסות בשל חשיפה לתנאי מזג אוויר.. המלצה: פירוק הריצוף הפגום, הכנת משטח תקני עם שכבת דבק מלאה, הנחה מחדש בשיטת סרוק כפול. עלות משוערת: ₪180-₪400 (למ"ר)', '**קובייה רטט לקויה — חלל מתחת לריצוף חיצוני** — אריחי ריצוף מרפסת או שביל חיצוני עם חללים מתחתיהם, נשמע צליל חלול בהקשה. מסוכן במיוחד במרפסות בשל חשיפה לתנאי מזג אוויר.. המלצה: פירוק הריצוף הפגום, הכנת משטח תקני עם שכבת דבק מלאה, הנחה מחדש בשיטת סרוק כפול. עלות משוערת: ₪180-₪400 (למ"ר)', 'ת"י 1555 חלק 3 — כיסוי דבק מינימלי של 80% נדרש בריצוף חיצוני ואזורים רטובים', 'ת"י 1555 חלק 3 — כיסוי דבק מינימלי של 80% נדרש בריצוף חיצוני ואזורים רטובים', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**רצף לא אחיד של אריחים בין חדרים** — חוסר רציפות בריצוף במעבר בין חדרים — אריחים שאינם מיושרים או מתחלפים בצורה לא אחידה בין המרחבים.. המלצה: התאמת הריצוף במעברים על ידי פירוק מקומי והנחה מחדש עם יישור מדויק. עלות משוערת: ₪200-₪500 (ליחידה)', '**רצף לא אחיד של אריחים בין חדרים** — חוסר רציפות בריצוף במעבר בין חדרים — אריחים שאינם מיושרים או מתחלפים בצורה לא אחידה בין המרחבים.. המלצה: התאמת הריצוף במעברים על ידי פירוק מקומי והנחה מחדש עם יישור מדויק. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 1555 חלק 3 — ריצוף חייב להיות רציף ומיושר במעברים בין חדרים, אלא אם כן צוין אחרת במפרט', 'ת"י 1555 חלק 3 — ריצוף חייב להיות רציף ומיושר במעברים בין חדרים, אלא אם כן צוין אחרת במפרט', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**אריח פגום מהמפעל — כתמים/שינוי גוון** — אריחים עם פגמים מהמפעל כגון כתמים, שינוי גוון בולט, נקודות שחורות, או גימור לא אחיד. לרוב נובע משימוש באריחים מסדרות ייצור שונות.. המלצה: החלפת האריחים הפגומים באריחים מאותה סדרת ייצור (LOT) כדי להבטיח אחידות. עלות משוערת: ₪100-₪300 (ליחידה)', '**אריח פגום מהמפעל — כתמים/שינוי גוון** — אריחים עם פגמים מהמפעל כגון כתמים, שינוי גוון בולט, נקודות שחורות, או גימור לא אחיד. לרוב נובע משימוש באריחים מסדרות ייצור שונות.. המלצה: החלפת האריחים הפגומים באריחים מאותה סדרת ייצור (LOT) כדי להבטיח אחידות. עלות משוערת: ₪100-₪300 (ליחידה)', 'ת"י 1555 חלק 1 — אריחים חייבים להיות ממוינים לפי דרגות איכות — דרגה ראשונה נדרשת למגורים', 'ת"י 1555 חלק 1 — אריחים חייבים להיות ממוינים לפי דרגות איכות — דרגה ראשונה נדרשת למגורים', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**סף דלת חסר או לא תקין** — סף (מפתן) בין שני סוגי ריצוף או בפתח דלת חסר, פגום, או לא מותקן כראוי. גורם למפגע בטיחותי ולחדירת מים.. המלצה: התקנת סף אלומיניום או פליז מתאים, הדבקה ועיגון מכני. עלות משוערת: ₪80-₪200 (ליחידה)', '**סף דלת חסר או לא תקין** — סף (מפתן) בין שני סוגי ריצוף או בפתח דלת חסר, פגום, או לא מותקן כראוי. גורם למפגע בטיחותי ולחדירת מים.. המלצה: התקנת סף אלומיניום או פליז מתאים, הדבקה ועיגון מכני. עלות משוערת: ₪80-₪200 (ליחידה)', 'ת"י 1555 חלק 3 — מעברים בין סוגי ריצוף שונים חייבים לכלול סף מתאים או פרופיל מעבר', 'ת"י 1555 חלק 3 — מעברים בין סוגי ריצוף שונים חייבים לכלול סף מתאים או פרופיל מעבר', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**ריצוף קרמיקה עם החלקה לא מספקת** — אריחי קרמיקה ברצפה עם מקדם החלקה נמוך מהנדרש, במיוחד באזורים רטובים כמו חדרי רחצה וכניסות. מהווה סכנת החלקה.. המלצה: החלפת האריחים באריחים עם מקדם החלקה מתאים (R10-R11 לאזורים רטובים) או יישום ציפוי אנטי-סליפ. עלות משוערת: ₪150-₪350 (למ"ר)', '**ריצוף קרמיקה עם החלקה לא מספקת** — אריחי קרמיקה ברצפה עם מקדם החלקה נמוך מהנדרש, במיוחד באזורים רטובים כמו חדרי רחצה וכניסות. מהווה סכנת החלקה.. המלצה: החלפת האריחים באריחים עם מקדם החלקה מתאים (R10-R11 לאזורים רטובים) או יישום ציפוי אנטי-סליפ. עלות משוערת: ₪150-₪350 (למ"ר)', 'ת"י 1555 חלק 1 — אריחי רצפה באזורים רטובים חייבים לעמוד בדרישת מקדם החלקה R10 לפחות', 'ת"י 1555 חלק 1 — אריחי רצפה באזורים רטובים חייבים לעמוד בדרישת מקדם החלקה R10 לפחות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**קרמיקה מנוקדת/מנומרת שלא בהתאם למפרט** — אריחי קרמיקה שהותקנו אינם תואמים את הדגם, הצבע או הגוון שנבחר על ידי הרוכש ומופיע במפרט הטכני.. המלצה: החלפת האריחים שאינם תואמים באריחים מהדגם הנכון בהתאם למפרט. עלות משוערת: ₪150-₪400 (למ"ר)', '**קרמיקה מנוקדת/מנומרת שלא בהתאם למפרט** — אריחי קרמיקה שהותקנו אינם תואמים את הדגם, הצבע או הגוון שנבחר על ידי הרוכש ומופיע במפרט הטכני.. המלצה: החלפת האריחים שאינם תואמים באריחים מהדגם הנכון בהתאם למפרט. עלות משוערת: ₪150-₪400 (למ"ר)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**מפלס ריצוף לא אחיד בין חדרים** — הפרש גובה בין ריצוף בחדרים שונים, יוצר מדרגה קטנה במעבר. מפגע בטיחותי ומעיד על תכנון או ביצוע לקוי של שכבת היישור.. המלצה: פירוק הריצוף באזור המעבר, תיקון שכבת היישור, הנחה מחדש עם מפלס אחיד. עלות משוערת: ₪250-₪600 (ליחידה)', '**מפלס ריצוף לא אחיד בין חדרים** — הפרש גובה בין ריצוף בחדרים שונים, יוצר מדרגה קטנה במעבר. מפגע בטיחותי ומעיד על תכנון או ביצוע לקוי של שכבת היישור.. המלצה: פירוק הריצוף באזור המעבר, תיקון שכבת היישור, הנחה מחדש עם מפלס אחיד. עלות משוערת: ₪250-₪600 (ליחידה)', 'ת"י 1555 חלק 3 — מפלס הריצוף חייב להיות אחיד בכל הדירה למעט אזורים רטובים שם נדרש הפרש גובה מבוקר', 'ת"י 1555 חלק 3 — מפלס הריצוף חייב להיות אחיד בכל הדירה למעט אזורים רטובים שם נדרש הפרש גובה מבוקר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**ריצוף פורצלן עם שריטות/סימנים** — שריטות או סימני שפשוף על אריחי פורצלן שנגרמו במהלך עבודות הבנייה, העברת ציוד כבד, או ניקוי לא מתאים.. המלצה: ליטוש מקצועי של האריחים הפגומים. אם השריטות עמוקות — החלפת האריח. עלות משוערת: ₪50-₪200 (ליחידה)', '**ריצוף פורצלן עם שריטות/סימנים** — שריטות או סימני שפשוף על אריחי פורצלן שנגרמו במהלך עבודות הבנייה, העברת ציוד כבד, או ניקוי לא מתאים.. המלצה: ליטוש מקצועי של האריחים הפגומים. אם השריטות עמוקות — החלפת האריח. עלות משוערת: ₪50-₪200 (ליחידה)', 'ת"י 1555 חלק 1 — אריחים חייבים להימסר ללא פגמים, שריטות או סימנים', 'ת"י 1555 חלק 1 — אריחים חייבים להימסר ללא פגמים, שריטות או סימנים', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**אי-התאמה בין ריצוף לפתח ניקוז** — ריצוף שאינו מותאם לפתח הניקוז (נקז רצפה) — האריח חוסם חלקית את הנקז, או שאין שיפוע מתאים לכיוון הנקז.. המלצה: חיתוך מדויק של האריחים סביב הנקז, תיקון השיפוע מכל הכיוונים. עלות משוערת: ₪200-₪450 (ליחידה)', '**אי-התאמה בין ריצוף לפתח ניקוז** — ריצוף שאינו מותאם לפתח הניקוז (נקז רצפה) — האריח חוסם חלקית את הנקז, או שאין שיפוע מתאים לכיוון הנקז.. המלצה: חיתוך מדויק של האריחים סביב הנקז, תיקון השיפוע מכל הכיוונים. עלות משוערת: ₪200-₪450 (ליחידה)', 'ת"י 1555 חלק 3 — ריצוף סביב נקזים חייב לאפשר ניקוז מלא עם שיפוע מכל הכיוונים לעבר הנקז', 'ת"י 1555 חלק 3 — ריצוף סביב נקזים חייב לאפשר ניקוז מלא עם שיפוע מכל הכיוונים לעבר הנקז', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**פלינטוס (סוקל) רופף או מנותק** — פלינטוס (רצועת ריצוף בתחתית הקיר) שאינו מודבק כראוי, זזה בלחיצה, או מנותק מהקיר. מאפשר חדירת לכלוך ומים.. המלצה: הסרת הפלינטוס, ניקוי המשטח, הדבקה מחדש בדבק C2 ומילוי סיליקון בפינה העליונה. עלות משוערת: ₪30-₪60 (למ"א)', '**פלינטוס (סוקל) רופף או מנותק** — פלינטוס (רצועת ריצוף בתחתית הקיר) שאינו מודבק כראוי, זזה בלחיצה, או מנותק מהקיר. מאפשר חדירת לכלוך ומים.. המלצה: הסרת הפלינטוס, ניקוי המשטח, הדבקה מחדש בדבק C2 ומילוי סיליקון בפינה העליונה. עלות משוערת: ₪30-₪60 (למ"א)', 'ת"י 1555 חלק 3 — פלינטוס חייב להיות מודבק באופן מלא לקיר ולרצפה ללא חללים', 'ת"י 1555 חלק 3 — פלינטוס חייב להיות מודבק באופן מלא לקיר ולרצפה ללא חללים', true, 'low');
