INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**התנפחות ריצוף — טנטינג** — אריחי רצפה שהתנפחו ועלו ממקומם (טנטינג). תופעה המלווה לרוב בצליל פקיעה ונגרמת מהתפשטות תרמית ללא תפרי התפשטות מספקים.. המלצה: פירוק הריצוף שנפגע, תיקון תשתית היישור, הנחה מחדש עם תפרי התפשטות תקניים. עלות משוערת: ₪200-₪450 (למ"ר)', '**התנפחות ריצוף — טנטינג** — אריחי רצפה שהתנפחו ועלו ממקומם (טנטינג). תופעה המלווה לרוב בצליל פקיעה ונגרמת מהתפשטות תרמית ללא תפרי התפשטות מספקים.. המלצה: פירוק הריצוף שנפגע, תיקון תשתית היישור, הנחה מחדש עם תפרי התפשטות תקניים. עלות משוערת: ₪200-₪450 (למ"ר)', 'ת"י 1555 חלק 3 — ריצוף חייב לכלול תפרי התפשטות למניעת טנטינג', 'ת"י 1555 חלק 3 — ריצוף חייב לכלול תפרי התפשטות למניעת טנטינג', true, 'critical');
