INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'ריצוף', '**שיפוע לקוי בריצוף מרפסת** — שיפוע ריצוף במרפסת לא מכוון לניקוז — מים נשארים על המשטח.. המלצה: פירוק ריצוף והנחה מחדש עם שיפוע תקני. עלות משוערת: ₪150-₪350 (למ"ר)', '**שיפוע לקוי בריצוף מרפסת** — שיפוע ריצוף במרפסת לא מכוון לניקוז — מים נשארים על המשטח.. המלצה: פירוק ריצוף והנחה מחדש עם שיפוע תקני. עלות משוערת: ₪150-₪350 (למ"ר)', 'ת"י 1555 / ת"י 1515.3 — שיפוע מינימלי במרפסת: 1.5% לכיוון הניקוז', 'ת"י 1555 / ת"י 1515.3 — שיפוע מינימלי במרפסת: 1.5% לכיוון הניקוז', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חיפוי קירות וקרמיקה', '**הצפה של דבק אריחים מהרובה** — דבק אריחים שעלה ובלט מתוך קווי הרובה בין האריחים. נראה כחומר לבן/אפור שאינו רובה. נגרם משימוש ביותר מדי דבק.. המלצה: הסרת הדבק העודף בעזרת כלי חד, ניקוי התפרים ומילוי מחדש ברובה נקייה. עלות משוערת: ₪25-₪50 (למ"ר)', '**הצפה של דבק אריחים מהרובה** — דבק אריחים שעלה ובלט מתוך קווי הרובה בין האריחים. נראה כחומר לבן/אפור שאינו רובה. נגרם משימוש ביותר מדי דבק.. המלצה: הסרת הדבק העודף בעזרת כלי חד, ניקוי התפרים ומילוי מחדש ברובה נקייה. עלות משוערת: ₪25-₪50 (למ"ר)', 'ת"י 1555 חלק 3 — דבק אריחים לא יבלוט מעבר לתפרי הרובה', 'ת"י 1555 חלק 3 — דבק אריחים לא יבלוט מעבר לתפרי הרובה', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חיפוי קירות וקרמיקה', '**חיפוי קירות חדר רחצה לא מלא** — חיפוי הקרמיקה בחדר הרחצה אינו מגיע לגובה הנדרש או שיש אזורים ללא חיפוי שהיו צריכים להיות מחופים לפי המפרט.. המלצה: השלמת חיפוי הקרמיקה עד לגובה הנדרש במפרט עם אריחים זהים. עלות משוערת: ₪150-₪350 (למ"ר)', '**חיפוי קירות חדר רחצה לא מלא** — חיפוי הקרמיקה בחדר הרחצה אינו מגיע לגובה הנדרש או שיש אזורים ללא חיפוי שהיו צריכים להיות מחופים לפי המפרט.. המלצה: השלמת חיפוי הקרמיקה עד לגובה הנדרש במפרט עם אריחים זהים. עלות משוערת: ₪150-₪350 (למ"ר)', 'ת"י 1555 חלק 3 — חיפוי קירות בחדרי רחצה חייב להתאים למפרט הטכני, בדרך כלל עד גובה התקרה או 2.10 מ'' לפחות', 'ת"י 1555 חלק 3 — חיפוי קירות בחדרי רחצה חייב להתאים למפרט הטכני, בדרך כלל עד גובה התקרה או 2.10 מ'' לפחות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חיפוי קירות וקרמיקה', '**סיליקון חסר או פגום בפינות רטובות** — סיליקון חסר, מתקלף, או מעופש בפינות ובמפגשים בחדרי רחצה ומטבח — בין קיר לרצפה, בין קיר לאמבטיה, סביב כיור.. המלצה: הסרת הסיליקון הישן, ניקוי ויובש של האזור, יישום סיליקון סניטרי אנטי-פטרייתי חדש. עלות משוערת: ₪30-₪80 (למ"א)', '**סיליקון חסר או פגום בפינות רטובות** — סיליקון חסר, מתקלף, או מעופש בפינות ובמפגשים בחדרי רחצה ומטבח — בין קיר לרצפה, בין קיר לאמבטיה, סביב כיור.. המלצה: הסרת הסיליקון הישן, ניקוי ויובש של האזור, יישום סיליקון סניטרי אנטי-פטרייתי חדש. עלות משוערת: ₪30-₪80 (למ"א)', 'ת"י 1555 חלק 3 — כל המפגשים בין משטחים באזורים רטובים חייבים להיות אטומים בסיליקון סניטרי', 'ת"י 1555 חלק 3 — כל המפגשים בין משטחים באזורים רטובים חייבים להיות אטומים בסיליקון סניטרי', true, 'medium');
